SELECT count(*) FROM movie_companies, title, company_name, cast_info, char_name, role_type, company_type, kind_type, movie_info WHERE movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.role_id = role_type.id AND movie_companies.company_type_id = company_type.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id;